   483 | // Decomposes \p V into a constant offset + list of pairs { Coefficient,
   484 | // Variable } where Coefficient * Variable. The sum of the constant offset and
   485 | // pairs equals \p V.
   486 | static Decomposition decompose(Value *V,
   487 |                                SmallVectorImpl<ConditionTy> &Preconditions,
   488 |                                bool IsSigned, const DataLayout &DL) {
