   504 | 
   505 |     return V;
   506 |   }
   507 | 
   508 |   // Don't handle integers > 64 bit. Our coefficients are 64-bit large, so
   509 |   // coefficient add/mul may wrap, while the operation in the full bit width
   510 |   // would not.
   511 |   if (!Ty->isIntegerTy() || Ty->getIntegerBitWidth() > 64)
   512 |     return V;
   513 | 
   514 |   bool IsKnownNonNegative = false;
   515 | 
   516 |   // Decompose \p V used with a signed predicate.
   517 |   if (IsSigned) {
   518 |     if (auto *CI = dyn_cast<ConstantInt>(V)) {
   519 |       if (canUseSExt(CI))
   520 |         return CI->getSExtValue();
   521 |     }
   522 |     Value *Op0;
   523 |     Value *Op1;
   524 | 
   525 |     if (match(V, m_SExt(m_Value(Op0))))
