   542 |       return ResA;
   543 |     }
   544 | 
   545 |     ConstantInt *CI;
   546 |     if (match(V, m_NSWMul(m_Value(Op0), m_ConstantInt(CI))) && canUseSExt(CI)) {
   547 |       auto Result = decompose(Op0, Preconditions, IsSigned, DL);
