   549 |       return Result;
   550 |     }
   551 | 
   552 |     // (shl nsw x, shift) is (mul nsw x, (1<<shift)), with the exception of
   553 |     // shift == bw-1.
   554 |     if (match(V, m_NSWShl(m_Value(Op0), m_ConstantInt(CI)))) {
   555 |       uint64_t Shift = CI->getValue().getLimitedValue();
