   592 |   Value *Op1;
   593 |   ConstantInt *CI;
   594 |   if (match(V, m_NUWAdd(m_Value(Op0), m_Value(Op1)))) {
   595 |     return MergeResults(Op0, Op1, IsSigned);
   596 |   }
   597 |   if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1)))) {
   598 |     if (!isKnownNonNegative(Op0, DL))
   599 |       Preconditions.emplace_back(CmpInst::ICMP_SGE, Op0,
   600 |                                  ConstantInt::get(Op0->getType(), 0));
   601 |     if (!isKnownNonNegative(Op1, DL))
   602 |       Preconditions.emplace_back(CmpInst::ICMP_SGE, Op1,
   603 |                                  ConstantInt::get(Op1->getType(), 0));
