   612 |         ConstantInt::get(Op0->getType(), CI->getSExtValue() * -1));
   613 |     return MergeResults(Op0, CI, true);
   614 |   }
   615 | 
   616 |   // Decompose or as an add if there are no common bits between the operands.
   617 |   if (match(V, m_DisjointOr(m_Value(Op0), m_ConstantInt(CI))))
